// Primary path: LeadSimple REST via the mapping adapter (ADR-4). All CRM
// specifics live in leadsimple-map.json; when the admin key arrives only
// that file changes. Retries 3x with 2s/8s/30s backoff (S2 spec), 10s
// timeout per attempt so a slow CRM can never stall the queue.
// Requires NODE_FUNCTION_ALLOW_BUILTIN=fs.
const fs = require('fs');
const MAP_PATH = '/home/node/.n8n/wgc/leadsimple-map.json';
const payload = $json.payload;
if (!payload || !payload.submission_id) throw new Error('WF-2 called without a canonical payload'); // fail loud

let map = { enabled: false };
try { map = JSON.parse(fs.readFileSync(MAP_PATH, 'utf8')); } catch (e) { /* adapter absent -> fallback path */ }

// Render the email-parse body (exact S2 template) up front; both the
// fallback email and the notification email reuse it.
function nv(v) { return v === null || v === undefined ? '' : String(v); }
const emailText = [
  'First Name: ' + nv(payload.first_name),
  'Last Name: ' + nv(payload.last_name),
  'Email: ' + nv(payload.email),
  'Phone: ' + nv(payload.phone),
  'Property Address: ' + nv(payload.property_address),
  'Beds: ' + nv(payload.beds) + '    Baths: ' + nv(payload.baths),
  'Message: ' + nv(payload.message),
  'Source: ' + nv(payload.source),
  'TCPA Consent: ' + nv(payload.consent.tcpa),
  'Consent Timestamp: ' + nv(payload.consent.timestamp),
  'Consent Text Version: ' + nv(payload.consent.text_version),
  'Submission ID: ' + nv(payload.submission_id)
].join('\n');

let deliveredApi = false;
let apiError = '';
if (map.enabled === true && map.url) {
  // Map canonical fields -> CRM fields via the adapter's field_map.
  const crmBody = {};
  for (const [ours, theirs] of Object.entries(map.field_map || {})) {
    const path = ours.split('.');
    let val = payload;
    for (const seg of path) val = val == null ? null : val[seg];
    crmBody[theirs] = val;
  }
  Object.assign(crmBody, map.static_fields || {});
  const headers = { 'Content-Type': 'application/json' };
  if (map.auth_header) headers[map.auth_header] = $env.LEADSIMPLE_API_KEY;
  const backoff = [2000, 8000, 30000];
  for (let attempt = 0; attempt < 3 && !deliveredApi; attempt++) {
    try {
      await this.helpers.httpRequest({ method: 'POST', url: map.url, headers, body: crmBody, json: true, timeout: 10000 });
      deliveredApi = true;
    } catch (e) {
      apiError = String(e.message || e);
      if (attempt < 2) await new Promise(function (r) { setTimeout(r, backoff[attempt]); });
    }
  }
}

return [{ json: {
  delivered_api: deliveredApi,
  api_error: apiError,
  email_text: emailText,
  submission_id: payload.submission_id,
  lead_name: payload.first_name + ' ' + payload.last_name
} }];

